// Watchlist of domains to monitor.
// PRODUCTION: replace this static array with a read from a DB,
// Google Sheet, or a domains.json object in storage.
const domains = [
  'example.com',
  'api.example.com',
  'shop.example.com',
  'mail.example.com'
];

return domains.map((d) => ({ json: { domain: d } }));

// WHOIS lookup failed (continueErrorOutput branch).
// Pass a minimal object so the domain is still scored on cert data.
const domain = $json.domain || ($('Check TLS Cert').item ? $('Check TLS Cert').item.json.domain : 'unknown');
return [{ json: { domain, whoisError: true } }];

// Combine the merged cert + whois items for one domain and compute severity.
// Merge (combine by position) gives two items per domain; fold them.
function daysUntil(value) {
  if (!value) return null;
  const t = Date.parse(value);
  if (Number.isNaN(t)) return null;
  return Math.floor((t - Date.now()) / 86400000);
}

function band(days) {
  if (days === null || days === undefined) return 'ok';
  if (days < 7) return 'critical';
  if (days < 21) return 'warning';
  return 'ok';
}

const rank = { ok: 0, warning: 1, critical: 2 };

// Reduce all incoming items into a per-domain record.
const byDomain = {};
for (const item of $input.all()) {
  const j = item.json || {};
  const domain = j.domain || (j.host) || 'unknown';
  byDomain[domain] = Object.assign(byDomain[domain] || { domain }, j);
}

const out = [];
for (const domain of Object.keys(byDomain)) {
  const r = byDomain[domain];

  // Defensive field extraction across common cert/whois shapes.
  const certExpiry = r.valid_till || r.cert_valid_to || r.notAfter || (r.cert && r.cert.valid_to) || null;
  const regExpiry = r.expiry_date || r.expiration_date || r.registry_expiry || (r.whois && r.whois.expires) || null;

  const certDays = daysUntil(certExpiry);
  const regDays = daysUntil(regExpiry);

  const certBand = band(certDays);
  const regBand = r.whoisError ? 'ok' : band(regDays);
  const severity = rank[certBand] >= rank[regBand] ? certBand : regBand;

  out.push({
    json: {
      domain,
      severity,
      certDays,
      regDays,
      certExpiry,
      regExpiry,
      whoisError: !!r.whoisError,
      note: r.whoisError ? 'WHOIS lookup failed; scored on cert only' : ''
    }
  });
}

return out;

// Idempotency layer. Suppress findings already alerted for the same UTC day.
// State persists in workflow static data across runs.
const staticData = $getWorkflowStaticData('global');
const today = new Date().toISOString().slice(0, 10); // YYYY-MM-DD (UTC)

if (staticData.alertDay !== today) {
  // New day: reset the dedup ledger.
  staticData.alertDay = today;
  staticData.alerted = {};
}
staticData.alerted = staticData.alerted || {};

const out = [];
for (const item of $input.all()) {
  const f = item.json;
  const key = `${f.domain}:${f.severity}`;

  // Always pass 'ok' through (used only for counts, never alerts) but mark suppressed.
  if (f.severity === 'ok') {
    out.push({ json: Object.assign({}, f, { suppressed: true }) });
    continue;
  }

  if (staticData.alerted[key]) {
    // Already alerted today at this severity: suppress.
    out.push({ json: Object.assign({}, f, { suppressed: true }) });
    continue;
  }

  staticData.alerted[key] = new Date().toISOString();
  out.push({ json: Object.assign({}, f, { suppressed: false }) });
}

return out;

