// Build a single digest sorted by severity (critical first).
const rank = { critical: 0, warning: 1, ok: 2 };
const rows = $input.all()
  .map((i) => i.json)
  .filter((f) => f && f.domain)
  .sort((a, b) => (rank[a.severity] ?? 9) - (rank[b.severity] ?? 9));

if (rows.length === 0) {
  return [{ json: { skip: true, html: '', text: 'No alertable findings today.' } }];
}

const esc = (s) => String(s == null ? '' : s).replace(/[&<>]/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;' }[c]));

const trHtml = rows.map((r) =>
  `<tr><td>${esc(r.domain)}</td><td>${esc(r.severity)}</td><td>${esc(r.certDays)}</td><td>${esc(r.regDays)}</td><td>${esc(r.note)}</td></tr>`
).join('');

const html = `<h2>SSL &amp; Domain Watchdog - ${new Date().toISOString().slice(0,10)}</h2>` +
  `<table border="1" cellpadding="6" cellspacing="0">` +
  `<tr><th>Domain</th><th>Severity</th><th>Cert days</th><th>Reg days</th><th>Note</th></tr>` +
  trHtml + `</table>`;

const lines = rows.map((r) => `• ${r.domain} [${r.severity}] cert ${r.certDays}d / reg ${r.regDays}d`);
const text = `SSL & Domain Watchdog digest\n` + lines.join('\n');

return [{ json: { skip: false, html, text, count: rows.length } }];
